// ─── v2.71: Log wrapper — silenzia in produzione ────────────────────────────
var _qvLog = (function() {
  var isProd = window.IS_PROD === true;
  return {
    info:  function() { if (!isProd) console.info.apply(console, arguments); },
    warn:  function() { console.warn.apply(console, arguments); }, // warn sempre visibile
    error: function() { console.error.apply(console, arguments); } // error sempre visibile
  };
})();

// ─── Language Detection (v3.94: single global definition) ───
var LANG = document.documentElement.lang || 'it';
// v4.63: three-language support (it | en | es).
// LANG3 is the single source of truth for the active language.
var LANG3 = (function() {
  var l = (document.documentElement.lang || '').toLowerCase();
  var p = (location.pathname || '').toLowerCase();
  if (l === 'es' || p.indexOf('_es') !== -1) return 'es';
  if (l === 'en' || p.indexOf('_en') !== -1) return 'en';
  return 'it';
}());
window.LANG3 = LANG3;
// isEN kept for backward compatibility with the ~950 existing ternaries.
// For Spanish we treat isEN=true so the UI falls back to English strings
// (never Italian) where a dedicated Spanish string is not provided; the
// data layer still prefers the ...Es/...ES fields when present.
var isEN = (LANG3 === 'en' || LANG3 === 'es');
window.isEN = isEN;
// v4.63: T(it, en, es) returns the string for the active language.
// es is optional; if omitted, Spanish falls back to the English string.
function T(it, en, es) {
  if (LANG3 === 'es') return (es !== undefined && es !== null) ? es : en;
  if (LANG3 === 'en') return en;
  return it;
}
window.T = T;

// ─── v4.61: Ferry legs overlay (red dashed) — single source of truth ───
// TRIP_COORDS index (0-based) of days whose leg arrives BY SEA (ferry).
// G8 Tallinn→Helsinki(idx7), G19 Gryllefjord→Andenes(idx18), G21 Vesterålen(idx20),
// G26 Moskenes→Bodø(idx25), G33 internal ferries(idx32), G35 Kristiansand→Hirtshals(idx34).
window.FERRY_DAY_IDX = [7, 18, 20, 25, 32, 34];
// Draws the ferry segments as a red dashed line on top of an existing route.
// routeCoords must be [HOME, day0, day1, ...] (HOME prepended), matching the app's route arrays.
window._drawFerryLegs = function(map, routeCoords) {
  try {
    if (!map || typeof L === 'undefined' || !Array.isArray(routeCoords)) return;
    // map may be a Leaflet Map OR a LayerGroup; both expose addTo-compatible add via polyline.addTo(map)
    window.FERRY_DAY_IDX.forEach(function(di) {
      // day di (0-based TRIP_COORDS) sits at routeCoords[di+1] because HOME is prepended.
      var iTo = di + 1;
      var iFrom = iTo - 1;
      if (iFrom < 0 || iTo >= routeCoords.length) return;
      var a = routeCoords[iFrom], b = routeCoords[iTo];
      if (!a || !b) return;
      L.polyline([a, b], {
        color: '#e53e3e', weight: 3, opacity: 0.9,
        dashArray: '2,9', lineCap: 'round', lineJoin: 'round',
        className: 'qv-ferry-leg'
      }).addTo(map);
    });
  } catch (e) { if (window._qvLog) window._qvLog.warn('ferry legs draw failed', e); }
};

// ─── v4.41 (Audit Option A): SINGLE SOURCE OF TRUTH for per-day COORDINATES ───
// Problem (from the data-architecture audit): each trip day stored its coordinates
// in THREE separate places — itinerario[].mapsUrl (data.js), DAYS_DATA[].meteo
// (days-data.js) and TRIP_COORDS[] (weather-coords.js). When one was updated and
// another forgotten, the weather/map silently pointed to the wrong place (the
// Riga-showing-Verona bug). We now make TRIP_COORDS the ONLY source for the
// weather/map coordinate of each day, and derive the others from it at runtime,
// so they can never diverge again. Static high/low/cond/daylight are preserved.
(function _syncCoordsFromTripCoords() {
  try {
    if (typeof TRIP_COORDS === 'undefined' || !Array.isArray(TRIP_COORDS)) return;
    // 1) Weather coordinates: DAYS_DATA[i].meteo.lat/lon  ←  TRIP_COORDS[i]
    if (typeof DAYS_DATA !== 'undefined' && Array.isArray(DAYS_DATA)) {
      for (var i = 0; i < DAYS_DATA.length; i++) {
        var tc = TRIP_COORDS[i];
        if (!tc || typeof tc.lat !== 'number' || typeof tc.lng !== 'number') continue;
        var d = DAYS_DATA[i];
        if (!d) continue;
        if (!d.meteo || typeof d.meteo !== 'object') d.meteo = {};
        d.meteo.lat = tc.lat;
        d.meteo.lon = tc.lng; // note: DAYS_DATA uses .lon, TRIP_COORDS uses .lng
      }
    }
    // 2) Map/itinerary day coordinate: expose a derived ._coords on each
    //    itinerario entry so geofencing and markers can use the single source
    //    instead of regex-parsing mapsUrl (which often points to a POI, not the
    //    overnight city). mapsUrl/links are left untouched (they are POI links).
    if (typeof itinerario !== 'undefined' && Array.isArray(itinerario)) {
      for (var j = 0; j < itinerario.length; j++) {
        var c = TRIP_COORDS[j];
        if (!c || typeof c.lat !== 'number' || typeof c.lng !== 'number') continue;
        if (itinerario[j]) itinerario[j]._coords = { lat: c.lat, lng: c.lng };
      }
    }
  } catch (e) {
    if (window.console && console.warn) console.warn('[coord-sync] skipped:', e);
  }
})();

// ─── v4.41: Coordinate consistency self-check (dev only) ────────────────
// Verifies that, after the sync above, every day's weather coordinate matches
// TRIP_COORDS. If anything ever diverges in the future, it is logged loudly in
// the console instead of silently showing the wrong city's weather/map.
(function _coordConsistencyCheck() {
  try {
    if (window.IS_PROD === true) return; // stay quiet for end users
    if (typeof TRIP_COORDS === 'undefined' || typeof DAYS_DATA === 'undefined') return;
    var issues = [];
    for (var i = 0; i < DAYS_DATA.length; i++) {
      var tc = TRIP_COORDS[i], d = DAYS_DATA[i];
      if (!tc || !d || !d.meteo) continue;
      if (Math.abs((d.meteo.lat || 0) - tc.lat) > 1e-6 || Math.abs((d.meteo.lon || 0) - tc.lng) > 1e-6) {
        issues.push('G' + (i + 1) + ': meteo(' + d.meteo.lat + ',' + d.meteo.lon + ') != TRIP_COORDS(' + tc.lat + ',' + tc.lng + ')');
      }
    }
    if (issues.length && window.console) {
      console.warn('[coord-check] ' + issues.length + ' day(s) with mismatched coordinates:\n' + issues.join('\n'));
    } else if (window.console && console.info) {
      console.info('[coord-check] OK — all ' + DAYS_DATA.length + ' days share one coordinate source.');
    }
  } catch (e) { /* never block startup */ }
})();

// ─── v2.96: LOCAL date key (YYYY-MM-DD in LOCAL time) ───
// BUG FIX: toISOString().slice(0,10) returns the UTC date. In Italy (UTC+1/+2),
// after ~22:00–23:00 local time the UTC date is already the NEXT day, so any
// "today" key built from toISOString() points to the wrong day in the evening.
// This caused daily-summary/curiosity/parking keys to be saved/looked-up on the
// wrong date. Use this helper for any "calendar day" key. (Keep toISOString only
// where a true UTC ISO timestamp is required, e.g. GPX export.)
window.localDateStr = function(d) {
  var x = d ? new Date(d) : new Date();
  var y = x.getFullYear();
  var m = String(x.getMonth() + 1).padStart(2, '0');
  var day = String(x.getDate()).padStart(2, '0');
  return y + '-' + m + '-' + day;
};


