// ═══════════════════════════════════════════════════════════════
// ─── v3.52: "ALTRO" PAGE TAB (replaces bottom sheet) ───
// ═══════════════════════════════════════════════════════════════
(function() {
  // Altro tile clicks → navigate to sub-section
  var altroPage = document.getElementById('tab-altro');
  if (!altroPage) return;

  altroPage.querySelectorAll('.altro-tile[data-goto]').forEach(function(tile) {
    tile.addEventListener('click', function() {
      var tabId = this.getAttribute('data-goto');
      if (window.switchTab) {
        window.switchTab(tabId);
        history.pushState(null, '', '#tab-' + tabId);
      }
      if (window.haptic) window.haptic(15);
    });
  });

  // Settings row clicks that navigate
  altroPage.querySelectorAll('.altro-setting-row[data-goto]').forEach(function(row) {
    row.addEventListener('click', function() {
      var tabId = this.getAttribute('data-goto');
      if (window.switchTab) {
        window.switchTab(tabId);
        history.pushState(null, '', '#tab-' + tabId);
      }
    });
  });

  // v4.51: Curiosità tile in Altro menu → opens the curiosity panel (parity with home menus)
  var altroCuriositaBtn = document.getElementById('altro-curiosita-btn');
  if (altroCuriositaBtn) {
    altroCuriositaBtn.addEventListener('click', function() {
      if (typeof window.openCuriosityPanel === 'function') window.openCuriosityPanel();
      if (window.haptic) window.haptic(15);
    });
  }

  // Search button in Altro page → opens global search overlay
  var altroSearchBtn = document.getElementById('altroSearchBtn');
  if (altroSearchBtn) {
    altroSearchBtn.addEventListener('click', function() {
      var searchOverlay = document.getElementById('searchOverlay');
      if (searchOverlay) {
        searchOverlay.classList.add('open');
        var searchInput = document.getElementById('search-input');
        if (searchInput) searchInput.focus();
      }
    });
  }

  // Notification toggle handled in notification section (line ~9231)

  // Show admin button if owner (on tab switch + auth state change + initial load)
  function _updateAltroAdmin() {
    var adminBtn = document.getElementById('altro-admin-btn');
    if (adminBtn && window.isOwner) adminBtn.style.display = '';
    var vTag = document.getElementById('altro-version-tag');
    if (vTag) vTag.textContent = 'v' + (window.__EXPECTED_VERSION__ || '?');
  }
  window.addEventListener('tabSwitched', function(e) {
    if (e.detail === 'altro') _updateAltroAdmin();
  });
  window.addEventListener('authStateChanged', function(e) {
    if (e.detail && e.detail.isOwner) {
      window.isOwner = true;
      _updateAltroAdmin();
    }
  });
  // Initial check (in case auth resolved before this code runs)
  setTimeout(_updateAltroAdmin, 1500);

  // v3.53: Logout button in Altro page + v3.62: Login button in Altro page
  var altroLogoutBtn = document.getElementById('altro-logout-btn');
  var altroLoginBtn = document.getElementById('altro-login-btn');
  function _updateAltroLogout() {
    var user = (typeof firebase !== 'undefined' && firebase.auth) ? firebase.auth().currentUser : null;
    if (altroLogoutBtn) altroLogoutBtn.style.display = user ? '' : 'none';
    if (altroLoginBtn) altroLoginBtn.style.display = user ? 'none' : '';
  }
  if (altroLoginBtn) {
    altroLoginBtn.addEventListener('click', function() {
      doGoogleSignIn(function(u) {
        if (window.showToast) window.showToast((isEN ? 'Welcome, ' : 'Benvenuto, ') + (u.displayName || u.email), 'success');
      });
    });
  }
  window.addEventListener('tabSwitched', function(e) {
    if (e.detail === 'altro') _updateAltroLogout();
  });
  window.addEventListener('authStateChanged', function() { _updateAltroLogout(); });
  setTimeout(_updateAltroLogout, 2000);
  if (altroLogoutBtn) {
    altroLogoutBtn.addEventListener('click', function() {
      var user = firebase.auth().currentUser;
      if (!user) return;
      showConfirm((isEN ? 'Logged in as: ' : 'Connesso come: ') + (user.displayName || user.email) + '\n\n' + (isEN ? 'Sign out?' : 'Disconnettersi?'), function() {
        firebase.auth().signOut().then(function() {
          if (typeof window.detachFirebaseListeners === 'function') {
            window.detachFirebaseListeners('chat');
            window.detachFirebaseListeners('diario');
            window.detachFirebaseListeners('posizione');
            window.detachFirebaseListeners('admin');
            window.detachFirebaseListeners('home');
          }
          showToast(isEN ? 'Signed out' : 'Disconnesso', 'info');
          setTimeout(function() { window.location.reload(); }, 500);
        });
      });
    });
  }
})();


